{
  "name": "SVG to PDF Pro",
  "description": "A high-performance web-based utility to convert multiple SVG files into high-quality PDF documents with drag-and-drop support."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback, useRef } from 'react';
import { jsPDF } from 'jspdf';
import 'svg2pdf.js';
import { 
  CloudArrowUpIcon, 
  DocumentIcon, 
  XMarkIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon
} from '@heroicons/react/24/outline';

interface FileItem {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'converting' | 'completed' | 'error';
  progress: number;
}

const App: React.FC = () => {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addFiles = (newFiles: File[]) => {
    const svgFiles = newFiles.filter(f => f.type === 'image/svg+xml' || f.name.toLowerCase().endsWith('.svg'));

    const mappedFiles: FileItem[] = svgFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      preview: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));

    setFiles(prev => [...prev, ...mappedFiles]);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => {
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) URL.revokeObjectURL(target.preview);
      return prev.filter(f => f.id !== id);
    });
  };

  const convertToPdf = async (item: FileItem) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'converting', progress: 30 } : f));

    try {
      const text = await item.file.text();
      const parser = new DOMParser();
      const svgDoc = parser.parseFromString(text, 'image/svg+xml');
      const svgElement = svgDoc.documentElement;

      if (svgElement.tagName.toLowerCase() !== 'svg') {
        throw new Error('Invalid SVG content');
      }

      // Get dimensions
      const width = parseFloat(svgElement.getAttribute('width') || '0') || svgElement.viewBox.baseVal.width || 500;
      const height = parseFloat(svgElement.getAttribute('height') || '0') || svgElement.viewBox.baseVal.height || 500;

      const pdf = new jsPDF({
        orientation: width > height ? 'l' : 'p',
        unit: 'pt',
        format: [width, height]
      });

      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, progress: 60 } : f));

      // Use svg2pdf.js via jspdf instance
      // Note: svg2pdf is automatically added to jsPDF prototype when imported
      await (pdf as any).svg(svgElement, {
        x: 0,
        y: 0,
        width,
        height
      });

      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, progress: 90 } : f));

      const fileName = item.file.name.replace(/\.svg$/i, '.pdf');
      pdf.save(fileName);

      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', progress: 100 } : f));
    } catch (error) {
      console.error('Conversion failed:', error);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', progress: 0 } : f));
    }
  };

  const convertAll = async () => {
    const pending = files.filter(f => f.status === 'pending' || f.status === 'error');
    for (const item of pending) {
      await convertToPdf(item);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <header className="text-center mb-12">
        <h1 className="text-4xl font-extrabold text-slate-900 mb-2 tracking-tight">
          SVG <span className="text-indigo-600">to</span> PDF Pro
        </h1>
        <p className="text-slate-500 text-lg">
          複数のSVGファイルをドラッグ＆ドロップで一括PDF変換。ブラウザ完結で安全・高速。
        </p>
      </header>

      <div
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
        className={`relative group border-2 border-dashed rounded-3xl p-12 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer mb-8 ${
          isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
            : 'border-slate-300 hover:border-indigo-400 bg-white hover:bg-slate-50'
        }`}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          accept=".svg" 
          className="hidden" 
          ref={fileInputRef}
          onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
        />

        <div className={`p-4 rounded-full mb-4 transition-colors duration-300 ${isDragging ? 'bg-indigo-100' : 'bg-slate-100 group-hover:bg-indigo-50'}`}>
          <CloudArrowUpIcon className={`w-12 h-12 ${isDragging ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-500'}`} />
        </div>

        <p className="text-lg font-semibold text-slate-700">
          ファイルをドロップするか、クリックして選択
        </p>
        <p className="text-slate-400 text-sm mt-1">
          SVGファイルを複数選択可能です
        </p>
      </div>

      {files.length > 0 && (
        <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h2 className="font-bold text-slate-800 flex items-center gap-2">
              <DocumentIcon className="w-5 h-5 text-indigo-500" />
              ファイルリスト ({files.length})
            </h2>
            <button 
              onClick={convertAll}
              disabled={!files.some(f => f.status === 'pending' || f.status === 'error')}
              className="px-6 py-2 bg-indigo-600 text-white rounded-full font-semibold hover:bg-indigo-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
            >
              <DocumentArrowDownIcon className="w-5 h-5" />
              すべてPDF化
            </button>
          </div>

          <ul className="divide-y divide-slate-50">
            {files.map((item) => (
              <li key={item.id} className="p-4 flex items-center gap-4 hover:bg-slate-50/50 transition-colors">
                <div className="w-16 h-16 bg-slate-100 rounded-lg overflow-hidden flex-shrink-0 border border-slate-200">
                  <img src={item.preview} alt="preview" className="w-full h-full object-contain p-1" />
                </div>

                <div className="flex-grow min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-slate-700 font-medium truncate pr-4">
                      {item.file.name}
                    </span>
                    <span className="text-xs text-slate-400 uppercase font-bold">
                      {(item.file.size / 1024).toFixed(1)} KB
                    </span>
                  </div>

                  {item.status === 'converting' && (
                    <div className="w-full bg-slate-100 h-1.5 rounded-full mt-2">
                      <div 
                        className="bg-indigo-500 h-full rounded-full transition-all duration-300"
                        style={{ width: `${item.progress}%` }}
                      />
                    </div>
                  )}

                  {item.status === 'completed' && (
                    <div className="flex items-center gap-1 text-emerald-600 text-sm font-medium mt-1">
                      <CheckCircleIcon className="w-4 h-4" />
                      完了
                    </div>
                  )}

                  {item.status === 'error' && (
                    <div className="text-rose-500 text-sm font-medium mt-1">
                      エラーが発生しました
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2">
                  {item.status === 'pending' || item.status === 'error' ? (
                    <button 
                      onClick={() => convertToPdf(item)}
                      className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                      title="変換"
                    >
                      <ArrowPathIcon className="w-6 h-6" />
                    </button>
                  ) : null}

                  <button 
                    onClick={() => removeFile(item.id)}
                    className="p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-full transition-colors"
                    title="削除"
                  >
                    <XMarkIcon className="w-6 h-6" />
                  </button>
                </div>
              </li>
            ))}
          </ul>
        </div>
      )}

      <footer className="mt-12 text-center text-slate-400 text-sm">
        <p>© 2024 SVG to PDF Converter. No files are uploaded to any server.</p>
      </footer>
    </div>
  );
};

export default App;

