import React, { useState, useCallback, useRef } from 'react';
import { jsPDF } from 'jspdf';
import 'svg2pdf.js';
import { 
  CloudArrowUpIcon, 
  DocumentIcon, 
  XMarkIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon,
  ShieldCheckIcon,
  LockClosedIcon,
  DocumentDuplicateIcon
} from '@heroicons/react/24/outline';

interface FileItem {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'converting' | 'completed' | 'error';
  progress: number;
}

const App: React.FC = () => {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addFiles = (newFiles: File[]) => {
    const svgFiles = newFiles.filter(f => f.type === 'image/svg+xml' || f.name.toLowerCase().endsWith('.svg'));

    const mappedFiles: FileItem[] = svgFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      preview: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));

    setFiles(prev => [...prev, ...mappedFiles]);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => {
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) URL.revokeObjectURL(target.preview);
      return prev.filter(f => f.id !== id);
    });
  };

  const convertAllToSinglePdf = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);

    try {
      let pdf: jsPDF | null = null;

      for (let i = 0; i < files.length; i++) {
        const item = files[i];
        setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'converting', progress: 50 } : f));

        const text = await item.file.text();
        const parser = new DOMParser();
        const svgDoc = parser.parseFromString(text, 'image/svg+xml');
        const svgElement = svgDoc.documentElement;

        if (svgElement.tagName.toLowerCase() !== 'svg') {
          throw new Error(`Invalid SVG content in ${item.file.name}`);
        }

        const svgAsSvg = svgElement as unknown as SVGSVGElement;
        const width = parseFloat(svgElement.getAttribute('width') || '0') || svgAsSvg.viewBox?.baseVal.width || 500;
        const height = parseFloat(svgElement.getAttribute('height') || '0') || svgAsSvg.viewBox?.baseVal.height || 500;

        if (!pdf) {
          pdf = new jsPDF({
            orientation: width > height ? 'l' : 'p',
            unit: 'pt',
            format: [width, height]
          });
        } else {
          pdf.addPage([width, height], width > height ? 'l' : 'p');
        }

        // svg2pdf rendering with text support improvements
        await (pdf as any).svg(svgElement, {
          x: 0,
          y: 0,
          width,
          height,
          loadExternalStyleSheets: true // Try to load styles that might affect text
        });

        setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', progress: 100 } : f));
      }

      if (pdf) {
        pdf.save('combined_documents.pdf');
      }
    } catch (error) {
      console.error('Conversion failed:', error);
      alert('変換中にエラーが発生しました。SVGファイルが正しい形式か確認してください。');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <header className="text-center mb-8">
        <div className="inline-flex items-center gap-2 bg-emerald-50 border border-emerald-100 px-4 py-1.5 rounded-full mb-4">
          <ShieldCheckIcon className="w-5 h-5 text-emerald-600" />
          <span className="text-emerald-700 text-sm font-semibold">100% ブラウザ内処理・プライバシー保護</span>
        </div>
        <h1 className="text-4xl font-extrabold text-slate-900 mb-2 tracking-tight">
          SVG <span className="text-indigo-600">to</span> PDF Pro
        </h1>
        <p className="text-slate-500 text-lg max-w-2xl mx-auto">
          機密情報を守りながら複数のSVGを1つのPDFに結合。
          文字化けを防ぐためブラウザの標準フォントを使用してレンダリングします。
        </p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="flex items-start gap-3 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <LockClosedIcon className="w-6 h-6 text-indigo-500 flex-shrink-0" />
          <div>
            <h3 className="font-semibold text-slate-800 text-sm">ローカル処理</h3>
            <p className="text-slate-500 text-xs">データはブラウザ内で処理され、外部に漏れることはありません。</p>
          </div>
        </div>
        <div className="flex items-start gap-3 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <DocumentDuplicateIcon className="w-6 h-6 text-indigo-500 flex-shrink-0" />
          <div>
            <h3 className="font-semibold text-slate-800 text-sm">自動結合</h3>
            <p className="text-slate-500 text-xs">選択したすべてのSVGをページ分けされた1つのPDFにまとめます。</p>
          </div>
        </div>
      </div>

      <div
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
        className={`relative group border-2 border-dashed rounded-3xl p-12 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer mb-8 ${
          isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
            : 'border-slate-300 hover:border-indigo-400 bg-white hover:bg-slate-50'
        }`}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          accept=".svg" 
          className="hidden" 
          ref={fileInputRef}
          onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
        />

        <div className={`p-4 rounded-full mb-4 transition-colors duration-300 ${isDragging ? 'bg-indigo-100' : 'bg-slate-100 group-hover:bg-indigo-50'}`}>
          <CloudArrowUpIcon className={`w-12 h-12 ${isDragging ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-500'}`} />
        </div>

        <p className="text-lg font-semibold text-slate-700">
          ファイルをドロップするか、クリックして選択
        </p>
        <p className="text-slate-400 text-sm mt-1">
          SVGファイルを複数選択可能です
        </p>
      </div>

      {files.length > 0 && (
        <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">
