        const result = await svgToDataUrl(item.file);

        if (i > 0) {
          pdf.addPage([result.width, result.height], result.width > result.height ? 'l' : 'p');
        } else {
          // 最初のページの設定
          pdf.deletePage(1);
          pdf.addPage([result.width, result.height], result.width > result.height ? 'l' : 'p');
        }

        pdf.addImage(result.dataUrl, 'PNG', 0, 0, result.width, result.height, undefined, 'FAST');

        setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', progress: 100 } : f));
      }

      pdf.save('converted_documents.pdf');
    } catch (error) {
      console.error('Conversion failed:', error);
      alert('変換中にエラーが発生しました。SVGファイル内のフォントや形式を確認してください。');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
