        <div className="flex items-start gap-3 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <LockClosedIcon className="w-6 h-6 text-indigo-500 flex-shrink-0" />
          <div>
            <h3 className="font-semibold text-slate-800 text-sm">ローカル処理</h3>
            <p className="text-slate-500 text-xs">データは送信されません。</p>
          </div>
        </div>
        <div className="flex items-start gap-3 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <DocumentDuplicateIcon className="w-6 h-6 text-indigo-500 flex-shrink-0" />
          <div>
            <h3 className="font-semibold text-slate-800 text-sm">全ファイルを結合</h3>
            <p className="text-slate-500 text-xs">複数ページとして1つのPDF化。</p>
          </div>
        </div>
