      setHistory(prev => [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date(),
        fileName: fileName,
        fileCount: files.length,
        url: pdfUrl
      }, ...prev]);

    } catch (error) {
      console.error('Conversion failed:', error);
      alert('変換中にエラーが発生しました。');
    } finally {
      setIsProcessing(false);
    }
  };

