export default App;

import React, { useState, useRef } from 'react';
import { jsPDF } from 'jspdf';
import { 
  CloudArrowUpIcon, 
  DocumentIcon, 
  XMarkIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon,
  ShieldCheckIcon,
  LockClosedIcon,
  DocumentDuplicateIcon,
  ExclamationTriangleIcon,
  ClockIcon,
  TrashIcon,
  ArrowDownTrayIcon,
  ShieldExclamationIcon,
  ExclamationCircleIcon
} from '@heroicons/react/24/outline';

interface FileItem {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'converting' | 'completed' | 'error';
  progress: number;
}

interface ConversionHistory {
  id: string;
  timestamp: Date;
  fileName: string;
  fileCount: number;
  url: string;
  size: string;
}

const App: React.FC = () => {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [history, setHistory] = useState<ConversionHistory[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addFiles = (newFiles: File[]) => {
    const svgFiles = newFiles.filter(f => f.type === 'image/svg+xml' || f.name.toLowerCase().endsWith('.svg'));
    if (svgFiles.length === 0 && newFiles.length > 0) {
      alert("SVGファイルを選択してください。");
      return;
    }
    const mappedFiles: FileItem[] = svgFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      preview: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));
    setFiles(prev => [...prev, ...mappedFiles]);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => setIsDragging(false);

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) URL.revokeObjectURL(target.preview);
      return prev.filter(f => f.id !== id);
    });
  };

  const clearFiles = () => {
    files.forEach(f => URL.revokeObjectURL(f.preview));
    setFiles([]);
  };

  const deleteHistory = (id: string) => {
    setHistory(prev => {
      const target = prev.find(h => h.id === id);
      if (target) URL.revokeObjectURL(target.url);
      return prev.filter(h => h.id !== id);
    });
  };

  const svgToDataUrl = (file: File): Promise<{ dataUrl: string; width: number; height: number }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const scale = 3; 
          canvas.width = img.width * scale;
          canvas.height = img.height * scale;
          const ctx = canvas.getContext('2d');
          if (!ctx) {
            reject(new Error('Canvas context error'));
            return;
          }
          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.scale(scale, scale);
          ctx.drawImage(img, 0, 0);
          resolve({
            dataUrl: canvas.toDataURL('image/png'),
            width: img.width,
            height: img.height
          });
        };
        img.onerror = () => reject(new Error('SVGの読み込みに失敗しました'));
        img.src = e.target?.result as string;
      };
      reader.onerror = () => reject(new Error('ファイルの読み取りに失敗しました'));
      reader.readAsDataURL(file);
    });
  };

  const convertAllToSinglePdf = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);

    try {
      const pdf = new jsPDF({
        unit: 'pt',
        compress: true
      });

      for (let i = 0; i < files.length; i++) {
        const item = files[i];
        setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'converting' } : f));

        try {
          const result = await svgToDataUrl(item.file);
          if (i > 0) {
            pdf.addPage([result.width, result.height], result.width > result.height ? 'l' : 'p');
          } else {
            pdf.deletePage(1);
            pdf.addPage([result.width, result.height], result.width > result.height ? 'l' : 'p');
          }
          pdf.addImage(result.dataUrl, 'PNG', 0, 0, result.width, result.height, undefined, 'FAST');
          setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed' } : f));
        } catch (err) {
          setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error' } : f));
          throw err;
        }
      }

      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
      const fileName = `converted_${timestamp}.pdf`;
      const pdfBlob = pdf.output('blob');
      const pdfUrl = URL.createObjectURL(pdfBlob);
      const sizeStr = (pdfBlob.size / 1024 / 1024).toFixed(2) + ' MB';

      pdf.save(fileName);

      setHistory(prev => [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date(),
        fileName: fileName,
        fileCount: files.length,
        url: pdfUrl,
        size: sizeStr
      }, ...prev]);

    } catch (error) {
      console.error('Conversion failed:', error);
      alert('変換中にエラーが発生しました。一部のSVGファイルが破損しているか、非対応の形式である可能性があります。');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 md:py-12">
      <header className="text-center mb-10">
        <div className="inline-flex items-center gap-2 bg-emerald-50 border border-emerald-100 px-4 py-2 rounded-full mb-6 shadow-sm">
          <ShieldCheckIcon className="w-5 h-5 text-emerald-600" />
          <span className="text-emerald-700 text-xs md:text-sm font-bold">完全ローカル処理：ファイルはサーバーに送信されず、情報漏洩しません</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-black text-slate-900 mb-4 tracking-tight">
          SVG <span className="text-indigo-600">to</span> PDF Pro
        </h1>
        <p className="text-slate-500 text-base md:text-lg max-w-2xl mx-auto leading-relaxed px-4">
          図面の文字を画像化して確実に再現。
          複数のSVGを1つのPDFに結合し、履歴からいつでも再ダウンロード可能です。
        </p>
      </header>

      {/* セキュリティアピール */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-100 flex items-center gap-5">
          <div className="bg-indigo-500/50 p-3 rounded-2xl">
            <LockClosedIcon className="w-8 h-8 text-indigo-100" />
          </div>
          <div>
            <h3 className="font-bold text-lg">プライバシー第一</h3>
            <p className="text-indigo-100 text-sm opacity-90">解析・変換はすべてブラウザ上で行われます。機密図面も安心です。</p>
          </div>
        </div>
        <div className="bg-white rounded-3xl p-6 border border-slate-200 shadow-sm flex items-center gap-5">
          <div className="bg-emerald-50 p-3 rounded-2xl">
            <ShieldExclamationIcon className="w-8 h-8 text-emerald-600" />
          </div>
          <div>
            <h3 className="font-bold text-slate-800 text-lg text-emerald-700">情報漏洩ゼロ</h3>
            <p className="text-slate-500 text-sm">外部サーバーへのアップロードは一切行われません。</p>
          </div>
        </div>
      </div>

      {/* ファイル選択エリア */}
      <div
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
        className={`relative group border-2 border-dashed rounded-[2.5rem] p-10 md:p-16 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer mb-10 ${
          isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
            : 'border-slate-300 hover:border-indigo-400 bg-white hover:bg-slate-50/50 shadow-sm'
        }`}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          accept=".svg" 
          className="hidden" 
          ref={fileInputRef}
          onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
        />
        <div className={`p-6 rounded-3xl mb-4 transition-colors duration-300 ${isDragging ? 'bg-indigo-100' : 'bg-slate-100 group-hover:bg-indigo-50'}`}>
          <CloudArrowUpIcon className={`w-12 h-12 md:w-16 md:h-16 ${isDragging ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-500'}`} />
        </div>
        <p className="text-xl md:text-2xl font-black text-slate-700">SVGをドロップまたはクリック</p>
        <p className="text-slate-400 text-sm mt-2 font-medium">複数の図面を一括で選択・処理できます</p>
      </div>

      {/* 現在のファイルリスト */}
      {files.length > 0 && (
        <div className="bg-white rounded-[2rem] shadow-2xl shadow-slate-200/50 overflow-hidden border border-slate-100 mb-12">
          <div className="px-6 py-5 border-b border-slate-100 flex flex-col sm:flex-row items-center justify-between bg-slate-50/50 gap-4">
            <h2 className="font-bold text-slate-800 flex items-center gap-2">
              <DocumentIcon className="w-6 h-6 text-indigo-500" />
              選択中のファイル ({files.length})
            </h2>
            <div className="flex gap-2 w-full sm:w-auto">
              <button 
                onClick={clearFiles}
                className="flex-1 sm:flex-none px-4 py-2 text-slate-500 hover:text-rose-600 font-bold text-sm transition-colors"
              >
                クリア
              </button>
              <button 
                onClick={convertAllToSinglePdf}
                disabled={isProcessing}
                className="flex-[2] sm:flex-none px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100"
              >
                {isProcessing ? (
                  <ArrowPathIcon className="w-5 h-5 animate-spin" />
                ) : (
                  <DocumentArrowDownIcon className="w-5 h-5" />
                )}
                PDFに出力
              </button>
            </div>
          </div>

          <ul className="max-h-96 overflow-y-auto divide-y divide-slate-50">
            {files.map((item) => (
              <li key={item.id} className="p-4 flex items-center gap-4 hover:bg-slate-50/30 transition-colors">
                <div className="w-14 h-14 bg-white rounded-2xl overflow-hidden flex-shrink-0 border border-slate-100 shadow-sm p-1">
                  <img src={item.preview} alt="preview" className="w-full h-full object-contain" />
                </div>
                <div className="flex-grow min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-slate-700 font-bold truncate pr-4 text-sm">{item.file.name}</span>
                    <span className="text-[10px] text-slate-400 font-black uppercase bg-slate-100 px-2 py-0.5 rounded-md">{(item.file.size / 1024).toFixed(1)} KB</span>
                  </div>
                  {item.status === 'converting' && (
                    <div className="w-full bg-slate-100 h-1.5 rounded-full mt-2 overflow-hidden relative">
                      <div className="bg-indigo-500 h-full w-full absolute animate-progress" />
                    </div>
                  )}
                  {item.status === 'completed' && (
                    <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-black uppercase mt-1">
                      <CheckCircleIcon className="w-3.5 h-3.5" /> 準備完了
                    </div>
                  )}
                  {item.status === 'error' && (
                    <div className="flex items-center gap-1 text-rose-500 text-[10px] font-black uppercase mt-1">
                      <ExclamationCircleIcon className="w-3.5 h-3.5" /> 読み取り失敗
                    </div>
                  )}
                </div>
                <button 
                  onClick={() => removeFile(item.id)}
                  disabled={isProcessing}
                  className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                >
                  <XMarkIcon className="w-6 h-6" />
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* 変換履歴 */}
      <section className="mb-12">
        <div className="flex items-center justify-between mb-6 px-2">
          <h2 className="text-2xl font-black text-slate-800 flex items-center gap-3">
            <ClockIcon className="w-7 h-7 text-slate-400" />
            変換履歴
          </h2>
