import React, { useState, useRef } from 'react';
import { jsPDF } from 'jspdf';
import { PDFDocument } from 'pdf-lib';
import { 
  CloudArrowUpIcon, 
  DocumentIcon, 
  XMarkIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon,
  ShieldCheckIcon,
  LockClosedIcon,
  DocumentDuplicateIcon,
  ExclamationTriangleIcon,
  ClockIcon,
  TrashIcon,
  ArrowDownTrayIcon,
  ShieldExclamationIcon,
  ExclamationCircleIcon,
  DocumentTextIcon
} from '@heroicons/react/24/outline';

interface FileItem {
  id: string;
  file: File;
  preview: string | null;
  type: 'svg' | 'pdf';
  status: 'pending' | 'converting' | 'completed' | 'error';
}

interface ConversionHistory {
  id: string;
  timestamp: Date;
  fileName: string;
  fileCount: number;
  url: string;
  size: string;
}

const App: React.FC = () => {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [history, setHistory] = useState<ConversionHistory[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(f => 
      f.type === 'image/svg+xml' || 
      f.name.toLowerCase().endsWith('.svg') || 
      f.type === 'application/pdf' || 
      f.name.toLowerCase().endsWith('.pdf')
    );

    if (validFiles.length === 0 && newFiles.length > 0) {
      alert("SVGまたはPDFファイルを選択してください。");
      return;
    }

    const mappedFiles: FileItem[] = validFiles.map(file => {
      const isPdf = file.type === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
      return {
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: isPdf ? null : URL.createObjectURL(file),
        type: isPdf ? 'pdf' : 'svg',
        status: 'pending'
      };
    });
    setFiles(prev => [...prev, ...mappedFiles]);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => setIsDragging(false);

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target && target.preview) URL.revokeObjectURL(target.preview);
      return prev.filter(f => f.id !== id);
    });
  };

  const clearFiles = () => {
    files.forEach(f => f.preview && URL.revokeObjectURL(f.preview));
    setFiles([]);
  };

  const deleteHistory = (id: string) => {
    setHistory(prev => {
      const target = prev.find(h => h.id === id);
      if (target) URL.revokeObjectURL(target.url);
      return prev.filter(h => h.id !== id);
    });
  };

  const svgToPdfBytes = async (file: File): Promise<Uint8Array> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const scale = 3; 
          canvas.width = img.width * scale;
          canvas.height = img.height * scale;
          const ctx = canvas.getContext('2d');
          if (!ctx) return reject(new Error('Canvas error'));

          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.scale(scale, scale);
          ctx.drawImage(img, 0, 0);

          const pdf = new jsPDF({
            unit: 'pt',
            format: [img.width, img.height],
            compress: true
          });
          pdf.addImage(canvas.toDataURL('image/png'), 'PNG', 0, 0, img.width, img.height, undefined, 'FAST');
          resolve(new Uint8Array(pdf.output('arraybuffer')));
        };
        img.onerror = () => reject(new Error('SVG load error'));
        img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
    });
  };

  const processAndMerge = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);

    try {
      const mergedPdf = await PDFDocument.create();

      for (const item of files) {
        setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'converting' } : f));

        try {
          let donorPdfBytes: Uint8Array;
          if (item.type === 'svg') {
            donorPdfBytes = await svgToPdfBytes(item.file);
          } else {
            donorPdfBytes = new Uint8Array(await item.file.arrayBuffer());
          }

          const donorPdf = await PDFDocument.load(donorPdfBytes);
          const pages = await mergedPdf.copyPages(donorPdf, donorPdf.getPageIndices());
          pages.forEach(page => mergedPdf.addPage(page));

          setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed' } : f));
        } catch (err) {
          setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error' } : f));
          throw err;
        }
      }

      const pdfBytes = await mergedPdf.save();
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
      const fileName = `merged_${timestamp}.pdf`;
      const pdfBlob = new Blob([pdfBytes], { type: 'application/pdf' });
      const pdfUrl = URL.createObjectURL(pdfBlob);
      const sizeStr = (pdfBlob.size / 1024 / 1024).toFixed(2) + ' MB';

      const link = document.createElement('a');
      link.href = pdfUrl;
      link.download = fileName;
      link.click();

      setHistory(prev => [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date(),
        fileName,
        fileCount: files.length,
        url: pdfUrl,
        size: sizeStr
      }, ...prev]);

    } catch (error) {
      console.error('Processing failed:', error);
      alert('結合中にエラーが発生しました。ファイルが破損している可能性があります。');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 md:py-12">
      <header className="text-center mb-10">
        <div className="inline-flex items-center gap-2 bg-emerald-50 border border-emerald-100 px-4 py-2 rounded-full mb-6 shadow-sm">
          <ShieldCheckIcon className="w-5 h-5 text-emerald-600" />
          <span className="text-emerald-700 text-xs md:text-sm font-bold">完全ローカル処理：サーバーに送信されず、情報漏洩しません</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-black text-slate-900 mb-4 tracking-tight">
          SVG & PDF <span className="text-indigo-600">Joiner</span> Pro
        </h1>
        <p className="text-slate-500 text-base md:text-lg max-w-2xl mx-auto leading-relaxed px-4">
          SVGのPDF化と、既存PDFの結合をこれ一つで。
          すべてのファイルはあなたのブラウザ内だけで処理され、安全に結合されます。
        </p>
      </header>

      {/* セキュリティ・インフォ */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-100 flex items-center gap-5">
          <div className="bg-indigo-500/50 p-3 rounded-2xl">
            <LockClosedIcon className="w-8 h-8 text-indigo-100" />
          </div>
          <div>
            <h3 className="font-bold text-lg">プライバシー第一</h3>
            <p className="text-indigo-100 text-sm opacity-90">解析・結合はすべてブラウザ上で行われます。機密図面も安心です。</p>
          </div>
        </div>
        <div className="bg-white rounded-3xl p-6 border border-slate-200 shadow-sm flex items-center gap-5">
          <div className="bg-emerald-50 p-3 rounded-2xl">
            <ShieldExclamationIcon className="w-8 h-8 text-emerald-600" />
          </div>
          <div>
            <h3 className="font-bold text-slate-800 text-lg text-emerald-700">情報漏洩ゼロ</h3>
            <p className="text-slate-500 text-sm">外部サーバーへのアップロードは一切行われません。漏洩リスクなし。</p>
          </div>
        </div>
      </div>

      {/* ファイル選択エリア */}
      <div
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
        className={`relative group border-2 border-dashed rounded-[2.5rem] p-10 md:p-16 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer mb-10 ${
          isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
            : 'border-slate-300 hover:border-indigo-400 bg-white hover:bg-slate-50/50 shadow-sm'
        }`}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          accept=".svg,.pdf" 
          className="hidden" 
          ref={fileInputRef}
          onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
        />
        <div className={`p-6 rounded-3xl mb-4 transition-colors duration-300 ${isDragging ? 'bg-indigo-100' : 'bg-slate-100 group-hover:bg-indigo-50'}`}>
          <CloudArrowUpIcon className={`w-12 h-12 md:w-16 md:h-16 ${isDragging ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-500'}`} />
        </div>
        <p className="text-xl md:text-2xl font-black text-slate-700">SVG/PDFをドロップまたはクリック</p>
        <p className="text-slate-400 text-sm mt-2 font-medium">SVGをPDF化しながら、他のPDFと1つにまとめます</p>
      </div>

      {/* ファイルリスト */}
      {files.length > 0 && (
        <div className="bg-white rounded-[2rem] shadow-2xl shadow-slate-200/50 overflow-hidden border border-slate-100 mb-12">
          <div className="px-6 py-5 border-b border-slate-100 flex flex-col sm:flex-row items-center justify-between bg-slate-50/50 gap-4">
            <h2 className="font-bold text-slate-800 flex items-center gap-2">
              <DocumentIcon className="w-6 h-6 text-indigo-500" />
              結合リスト ({files.length})
            </h2>
            <div className="flex gap-2 w-full sm:w-auto">
              <button onClick={clearFiles} className="flex-1 sm:flex-none px-4 py-2 text-slate-500 hover:text-rose-600 font-bold text-sm transition-colors">クリア</button>
              <button 
                onClick={processAndMerge}
                disabled={isProcessing}
                className="flex-[2] sm:flex-none px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 disabled:bg-slate-300 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100"
              >
                {isProcessing ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : <DocumentArrowDownIcon className="w-5 h-5" />}
                1つのPDFに結合
              </button>
            </div>
          </div>

          <ul className="max-h-96 overflow-y-auto divide-y divide-slate-50">
            {files.map((item) => (
              <li key={item.id} className="p-4 flex items-center gap-4 hover:bg-slate-50/30 transition-colors">
                <div className="w-14 h-14 bg-white rounded-2xl overflow-hidden flex-shrink-0 border border-slate-100 shadow-sm flex items-center justify-center">
                  {item.type === 'svg' && item.preview ? (
                    <img src={item.preview} alt="preview" className="w-full h-full object-contain p-1" />
                  ) : (
                    <DocumentTextIcon className="w-8 h-8 text-indigo-400" />
                  )}
                </div>
                <div className="flex-grow min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-slate-700 font-bold truncate pr-4 text-sm">{item.file.name}</span>
                    <span className="text-[10px] text-slate-400 font-black uppercase bg-slate-100 px-2 py-0.5 rounded-md">
                      {item.type} • {(item.file.size / 1024).toFixed(1)} KB
                    </span>
                  </div>
                  {item.status === 'converting' && (
                    <div className="w-full bg-slate-100 h-1.5 rounded-full mt-2 overflow-hidden relative">
                      <div className="bg-indigo-500 h-full w-full absolute animate-progress" />
                    </div>
                  )}
                  {item.status === 'completed' && <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-black uppercase mt-1"><CheckCircleIcon className="w-3.5 h-3.5" /> 処理済み</div>}
                  {item.status === 'error' && <div className="flex items-center gap-1 text-rose-500 text-[10px] font-black uppercase mt-1"><ExclamationCircleIcon className="w-3.5 h-3.5" /> エラー</div>}
                </div>
                <button onClick={() => removeFile(item.id)} disabled={isProcessing} className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all">
                  <XMarkIcon className="w-6 h-6" />
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* 履歴セクション */}
      <section className="mb-12">
        <h2 className="text-2xl font-black text-slate-800 flex items-center gap-3 mb-6 px-2">
          <ClockIcon className="w-7 h-7 text-slate-400" /> 変換・結合履歴
        </h2>
        {history.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-[2.5rem] border-4 border-dotted border-slate-100 text-slate-400 font-bold italic">履歴はありません</div>
