        </div>
        <h1 className="text-4xl md:text-5xl font-black text-slate-900 mb-4 tracking-tight">
          SVG & PDF <span className="text-indigo-600">Joiner</span> Pro
        </h1>
        <p className="text-slate-500 text-base md:text-lg max-w-2xl mx-auto leading-relaxed px-4">
          SVGをPDFに変換し、他のPDFと自由に並び替えて1つに結合。
          追加のD&Dも可能。すべての作業はブラウザ内で完結します。
        </p>
      </header>

      {/* ドロップゾーン */}
      <div
        onDragOver={onDragOverZone}
        onDragLeave={() => setIsDraggingOver(false)}
        onDrop={onDropZone}
        className={`relative group border-2 border-dashed rounded-[2.5rem] p-10 md:p-14 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer mb-10 ${
          isDraggingOver 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
            : 'border-slate-300 hover:border-indigo-400 bg-white hover:bg-slate-50/50 shadow-sm'
        }`}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          accept=".svg,.pdf" 
          className="hidden" 
          ref={fileInputRef}
          onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
        />
        <div className={`p-6 rounded-3xl mb-4 transition-colors duration-300 ${isDraggingOver ? 'bg-indigo-100' : 'bg-slate-100 group-hover:bg-indigo-50'}`}>
          <CloudArrowUpIcon className={`w-12 h-12 md:w-16 md:h-16 ${isDraggingOver ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-500'}`} />
        </div>
        <p className="text-xl md:text-2xl font-black text-slate-700 text-center">SVG/PDFを追加ドロップ</p>
        <p className="text-slate-400 text-sm mt-2 font-medium">いつでもファイルを追加してリストを構成できます</p>
      </div>

      {/* ファイルリスト (並び替え可能) */}
      {files.length > 0 && (
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 overflow-hidden border border-slate-100 mb-12">
          <div className="px-8 py-6 border-b border-slate-100 flex flex-col sm:flex-row items-center justify-between bg-slate-50/50 gap-4">
            <div>
              <h2 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                <DocumentIcon className="w-6 h-6 text-indigo-500" />
                結合待ちリスト ({files.length})
              </h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest">アイテムをドラッグして順序を入れ替え</p>
            </div>
            <div className="flex gap-2 w-full sm:w-auto">
              <button onClick={() => {
                files.forEach(f => f.preview && URL.revokeObjectURL(f.preview));
                setFiles([]);
              }} className="flex-1 sm:flex-none px-5 py-2 text-slate-400 hover:text-rose-600 font-black text-xs transition-colors uppercase tracking-widest">すべてクリア</button>
              <button 
                onClick={processAndMerge}
                disabled={isProcessing}
                className="flex-[2] sm:flex-none px-8 py-3 bg-indigo-600 text-white rounded-2xl font-black text-sm hover:bg-indigo-700 disabled:bg-slate-300 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-200"
              >
                {isProcessing ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : <DocumentArrowDownIcon className="w-5 h-5" />}
                1つのPDFに結合
              </button>
            </div>
          </div>

          <ul className="max-h-[500px] overflow-y-auto divide-y divide-slate-100">
            {files.map((item, index) => (
              <li 
                key={item.id} 
                draggable
                onDragStart={() => onDragStartItem(index)}
                onDragOver={(e) => onDragOverItem(e, index)}
                onDragEnd={onDragEndItem}
                className={`p-5 flex items-center gap-4 hover:bg-slate-50 transition-all cursor-move group ${
                  draggedItemIndex === index ? 'opacity-30 bg-indigo-50' : ''
                }`}
              >
                <div className="text-slate-300 group-hover:text-indigo-400 transition-colors">
                  <Bars3Icon className="w-6 h-6" />
                </div>

                <div className="w-16 h-16 bg-white rounded-2xl overflow-hidden flex-shrink-0 border border-slate-100 shadow-sm flex items-center justify-center">
                  {item.type === 'svg' && item.preview ? (
                    <img src={item.preview} alt="preview" className="w-full h-full object-contain p-2" />
                  ) : (
                    <div className="flex flex-col items-center">
                       <DocumentTextIcon className="w-8 h-8 text-indigo-400" />
                       <span className="text-[8px] font-black text-indigo-300 uppercase">PDF</span>
                    </div>
                  )}
                </div>

                <div className="flex-grow min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-slate-700 font-bold truncate pr-4 text-sm">{item.file.name}</span>
                    <span className="text-[10px] text-slate-400 font-black uppercase bg-slate-100 px-2 py-0.5 rounded-md">
                      {item.type} • {(item.file.size / 1024).toFixed(1)} KB
                    </span>
                  </div>
                  {item.status === 'converting' && (
                    <div className="w-full bg-slate-100 h-1.5 rounded-full mt-2 overflow-hidden relative">
                      <div className="bg-indigo-500 h-full w-full absolute animate-progress" />
                    </div>
                  )}
                  {item.status === 'completed' && <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-black uppercase mt-1"><CheckCircleIcon className="w-3.5 h-3.5" /> 処理済み</div>}
                  {item.status === 'error' && <div className="flex items-center gap-1 text-rose-500 text-[10px] font-black uppercase mt-1"><ExclamationCircleIcon className="w-3.5 h-3.5" /> エラー</div>}
                  {item.status === 'pending' && <div className="text-slate-300 text-[9px] font-bold uppercase mt-1">待機中 (結合順位: {index + 1})</div>}
                </div>

                <button 
                  onClick={() => removeFile(item.id)} 
                  disabled={isProcessing} 
                  className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"
                >
                  <XMarkIcon className="w-6 h-6" />
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* 履歴 */}
      <section className="mb-12">
        <h2 className="text-2xl font-black text-slate-800 flex items-center gap-3 mb-6 px-2">
          <ClockIcon className="w-7 h-7 text-slate-400" /> 出力履歴
        </h2>
        {history.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-[2.5rem] border-4 border-dotted border-slate-100 text-slate-400 font-bold italic">履歴はありません</div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {history.map((item) => (
              <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-4 group hover:shadow-md transition-shadow">
                <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center flex-shrink-0"><DocumentDuplicateIcon className="w-7 h-7 text-indigo-600" /></div>
                <div className="flex-grow min-w-0">
                  <h3 className="text-slate-800 font-black truncate text-sm mb-1">{item.fileName}</h3>
                  <div className="flex items-center gap-2 text-[10px] text-slate-400 font-black uppercase tracking-widest">
                    <span className="bg-slate-100 px-2 py-0.5 rounded text-indigo-600">{item.fileCount} ファイル</span>
                    <span>{item.size}</span>
                    <span>•</span>
                    <span>{item.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  <a href={item.url} download={item.fileName} className="p-3 text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50 rounded-2xl transition-all"><ArrowDownTrayIcon className="w-6 h-6" /></a>
                  <button onClick={() => deleteHistory(item.id)} className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"><TrashIcon className="w-6 h-6" /></button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* セキュリティ詳細 */}
      <div className="bg-slate-900 text-slate-400 p-8 md:p-10 rounded-[3rem] shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none"><ShieldCheckIcon className="w-40 h-40 text-white" /></div>
        <div className="relative z-10 flex flex-col md:flex-row gap-8 items-start">
          <div className="bg-slate-800 p-5 rounded-3xl"><ExclamationTriangleIcon className="w-10 h-10 text-amber-500" /></div>
          <div className="text-xs md:text-sm leading-relaxed">
            <p className="text-slate-100 font-black text-lg md:text-xl mb-3 tracking-tight">安全へのこだわり</p>
            <p className="mb-4 text-slate-300">
              本ツールは「追加D&D」「並び替え」を含むすべての操作を, あなたのPC内のブラウザメモリ上でのみ実行します。インターネットを通じてファイルが外部に流出することはありません。
            </p>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-[10px] font-black uppercase tracking-[0.2em]">
              <div className="flex items-center gap-2"><CheckCircleIcon className="w-4 h-4 text-emerald-500" /> サーバー送信なし</div>
              <div className="flex items-center gap-2"><CheckCircleIcon className="w-4 h-4 text-emerald-500" /> 秘密保持</div>
              <div className="flex items-center gap-2"><CheckCircleIcon className="w-4 h-4 text-emerald-500" /> ローカル完結型</div>
              <div className="flex items-center gap-2"><CheckCircleIcon className="w-4 h-4 text-emerald-500" /> 安全なマージ</div>
            </div>
          </div>
        </div>
      </div>

      <footer className="mt-20 text-center border-t border-slate-200 pt-10">
        <p className="text-slate-400 text-[10px] font-black opacity-50 italic uppercase tracking-[0.3em]">
          SVG & PDF Joiner Pro • Privacy-First Productivity Tool
        </p>
      </footer>
    </div>
  );
};

export default App;

